mapper.select:
select P.VHPLNKY as vhplnky
from TVHCPL P
where P.COMPKEY = #{compkey}
  and P.SHTRTKY = #{shtrtky}
  and P.VEHICKY = #{vehicky}
  and P.SHTRSTS != 'CMP'
group by P.VHPLNKY

select VHCFNAM
  from MVHCMA
 where COMPKEY = #{compkey}
   and VEHICKY = #{vehicky}

mapper.update:
update TVHCPL
   set SHTRSTS = 'CMP'
     , LMODATE = TO_CHAR(NOW(), 'YYYYMMDD')
     , LMOTIME = TO_CHAR(NOW(), 'hh24miss')
     , LMOUSER = #{lmouser}
 where 1=1
   and COMPKEY = #{compkey}
   and VHPLNKY = #{vhplnky}

update TVHCPL
 set SHTRSTS = 'ING'
  ,  RSNCODE = #{rsncode}
  ,  RSNREMK = #{rsnremk}
  ,  REPITDT = TO_CHAR(NOW(), 'YYYYMMDD')
  ,  REPITTM = TO_CHAR(NOW(), 'hh24miss')
  ,  LMODATE = TO_CHAR(NOW(), 'YYYYMMDD')
  ,  LMOTIME = TO_CHAR(NOW(), 'hh24miss')
  ,  LMOUSER = #{lmouser}
 where 1=1
  and COMPKEY = #{compkey}
  and VHPLNKY = #{vhplnky}
  and VHPLNIT = #{vhplnit}

mapper.select:
select date_format(P.VHPDATE ,'%Y-%m-%d') as vhpdate , concat(SUBSTR(P.VHPTIME,1,2), ':' , SUBSTR(P.VHPTIME,3,2) , ':', SUBSTR(P.VHPTIME,4,2)) as vhptime , P.VEHICKY as vehicky , P.VHPLNKY, ifnull(T.LABRLTX,'') as labrltx, ifnull(T.DABONYN,'N') as dabonyn, group_concat(case P.VHPLNIT when 1 then M.CUSTKEY end) as pos01ct , group_concat(case P.VHPLNIT when 2 then M.CUSTKEY end) as pos02ct , group_concat(case P.VHPLNIT when 3 then M.CUSTKEY end) as pos03ct , group_concat(case P.VHPLNIT when 4 then M.CUSTKEY end) as pos04ct , group_concat(case P.VHPLNIT when 5 then M.CUSTKEY end) as pos05ct , group_concat(case P.VHPLNIT when 6 then M.CUSTKEY end) as pos06ct , group_concat(case P.VHPLNIT when 7 then M.CUSTKEY end) as pos07ct , group_concat(case P.VHPLNIT when 8 then M.CUSTKEY end) as pos08ct , group_concat(case P.VHPLNIT when 1 then P.SHTRSTS end) as pos01st , group_concat(case P.VHPLNIT when 2 then P.SHTRSTS end) as pos02st , group_concat(case P.VHPLNIT when 3 then P.SHTRSTS end) as pos03st , group_concat(case P.VHPLNIT when 4 then P.SHTRSTS end) as pos04st , group_concat(case P.VHPLNIT when 5 then P.SHTRSTS end) as pos05st , group_concat(case P.VHPLNIT when 6 then P.SHTRSTS end) as pos06st , group_concat(case P.VHPLNIT when 7 then P.SHTRSTS end) as pos07st , group_concat(case P.VHPLNIT when 8 then P.SHTRSTS end) as pos08st , group_concat(case P.VHPLNIT when 1 then H.CUNAMLC end) as pos01nm , group_concat(case P.VHPLNIT when 2 then H.CUNAMLC end) as pos02nm , group_concat(case P.VHPLNIT when 3 then H.CUNAMLC end) as pos03nm , group_concat(case P.VHPLNIT when 4 then H.CUNAMLC end) as pos04nm , group_concat(case P.VHPLNIT when 5 then H.CUNAMLC end) as pos05nm , group_concat(case P.VHPLNIT when 6 then H.CUNAMLC end) as pos06nm , group_concat(case P.VHPLNIT when 7 then H.CUNAMLC end) as pos07nm , group_concat(case P.VHPLNIT when 8 then H.CUNAMLC end) as pos08nm , group_concat(case P.VHPLNIT when 1 then C.COMCDTX end) as pos01ty , group_concat(case P.VHPLNIT when 2 then C.COMCDTX end) as pos02ty , group_concat(case P.VHPLNIT when 3 then C.COMCDTX end) as pos03ty , group_concat(case P.VHPLNIT when 4 then C.COMCDTX end) as pos04ty , group_concat(case P.VHPLNIT when 5 then C.COMCDTX end) as pos05ty , group_concat(case P.VHPLNIT when 6 then C.COMCDTX end) as pos06ty , group_concat(case P.VHPLNIT when 7 then C.COMCDTX end) as pos07ty , group_concat(case P.VHPLNIT when 8 then C.COMCDTX end) as pos08ty , count(1) as coldcnt , (select COMCDTX from V_MCODEM c where C.COMPKEY = #{userInfo.compkey} and C.COMCDKY='SHTRPTY' and COMCDVL=M.SHTRPTY) as shtrpnm from TVHCPL P inner join MSHRIT M on M.COMPKEY = P.COMPKEY and M.SHTRTKY = P.SHTRTKY and M.SHTRTIT = P.SHTRTIT inner join MCUSMA H on H.COMPKEY = M.COMPKEY and H.CUSTKEY = M.CUSTKEY inner join V_MCODEM C on C.COMPKEY = M.COMPKEY and C.COMCDKY = 'SHTRPTY' and C.COMCDVL = M.SHTRPTY left join ( select A.COMPKEY, A.VHPLNKY , GROUP_CONCAT(A.LABRLTX) as LABRLTX , A.DABONYN from ( select WL.COMPKEY, WL.VHPLNKY , concat(' ', WL.CUNAMLC , ' ' , count(1), ' ' ) as LABRLTX , (case when count(1) > 0 then 'Y' else 'N' end) as DABONYN from WSLBMA WL where WL.COMPKEY = #{userInfo.compkey} and WL.CUSTKEY in (
select CUSTKEY from SUSRMA SU where SU.COMPKEY = #{userInfo.compkey} and SU.USERACT = #{userInfo.useract}
select CUSTKEY from MCUSMA M where M.COMPKEY = #{userInfo.compkey} and M.OWNERKY in (select OWNERKY from SUSRMA SU where SU.COMPKEY = #{userInfo.compkey} and SU.USERACT = #{userInfo.useract}) and M.CUSTTYP = 'WHOLESALE'
select CUSTKEY from MCUSMA M where M.COMPKEY = #{userInfo.compkey} and M.CUSTTYP = 'WHOLESALE'
) group by WL.COMPKEY, WL.VHPLNKY, WL.CUNAMLC ) A where 1=1 group by A.COMPKEY, A.VHPLNKY ) T on T.COMPKEY = P.COMPKEY and T.VHPLNKY = P.VHPLNKY where P.COMPKEY = #{userInfo.compkey}
and P.VHPDATE between replace(#{vhpStrDate}, '-' , '') and replace(#{vhpEndDate}, '-' , '')
and P.VEHICKY = #{vehicky}
and M.SHTRTKY = #{shtrtnm}
group by P.VHPDATE , P.VHPTIME , P.VEHICKY order by P.VHPDATE desc , P.VHPTIME desc , P.VEHICKY
